diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..6222f7684bdf 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3004,6 +3004,76 @@ foldRoundUpIntegerWithPow2Alignment(SelectInst &SI,
   return R;
 }

+/// Fold symmetric nested selects where the two inner selects have the same
+/// condition but swapped true/false values.
+/// Pattern:
+///   %sel1 = select i1 %c1, T %a, T %b
+///   %sel2 = select i1 %c1, T %b, T %a
+///   %ret = select i1 %c2, T %sel1, T %sel2
+/// Transforms to:
+///   %xor = xor i1 %c1, %c2
+///   %ret = select i1 %xor, T %b, T %a
+///
+/// Also handles the commuted case:
+///   %ret = select i1 %c2, T %sel2, T %sel1
+/// Transforms to:
+///   %xor = xor i1 %c1, %c2
+///   %ret = select i1 %xor, T %a, T %b
+static Instruction *foldSymmetricSelects(SelectInst &SI,
+                                         InstCombiner::BuilderTy &Builder) {
+  Value *Cond = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+
+  // Both operands must be selects.
+  auto *TrueSI = dyn_cast<SelectInst>(TrueVal);
+  auto *FalseSI = dyn_cast<SelectInst>(FalseVal);
+  if (!TrueSI || !FalseSI)
+    return nullptr;
+
+  // Inner selects must have the same condition.
+  Value *InnerCond = TrueSI->getCondition();
+  if (InnerCond != FalseSI->getCondition())
+    return nullptr;
+
+  // Condition types must match for XOR.
+  if (InnerCond->getType() != Cond->getType())
+    return nullptr;
+
+  // Profitability check: inner selects should have only one use (this select).
+  // Otherwise we would be replacing 1 select + 1 xor with 1 select, but the inner
+  // selects would still need to exist for their other uses.
+  if (!TrueSI->hasOneUse() || !FalseSI->hasOneUse())
+    return nullptr;
+
+  Value *A = TrueSI->getTrueValue();
+  Value *B = TrueSI->getFalseValue();
+
+  // Check if the true/false values are swapped (symmetric pattern).
+  // Pattern 1: sel1 = c1 ? a : b, sel2 = c1 ? b : a, ret = c2 ? sel1 : sel2
+  if (FalseSI->getTrueValue() == B && FalseSI->getFalseValue() == A) {
+    // ret = c2 ? (c1 ? a : b) : (c1 ? b : a)
+    //     = (c1 == c2) ? a : b
+    //     = (c1 XOR c2) ? b : a
+    Value *XorCond = Builder.CreateXor(InnerCond, Cond);
+    return SelectInst::Create(XorCond, B, A);
+  }
+
+  // Pattern 2 (commuted): sel1 = c1 ? a : b, sel2 = c1 ? b : a, ret = c2 ? sel2 : sel1
+  if (FalseSI->getTrueValue() == A && FalseSI->getFalseValue() == B) {
+    // ret = c2 ? (c1 ? b : a) : (c1 ? a : b)
+    //     = (c1 == c2) ? b : a
+    //     = (c1 XOR c2) ? a : b
+    Value *XorCond = Builder.CreateXor(InnerCond, Cond);
+    return SelectInst::Create(XorCond, A, B);
+  }
+
+  return nullptr;
+}
+
+
+
+
 namespace {
 struct DecomposedSelect {
   Value *Cond = nullptr;
@@ -3987,9 +4057,11 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

-  if (Instruction *I = foldNestedSelects(SI, Builder))
+  if (Instruction *I = foldSymmetricSelects(SI, Builder))
     return I;

+  if (Instruction *I = foldNestedSelects(SI, Builder))
+    return I;
   // Match logical variants of the pattern,
   // and transform them iff that gets rid of inversions.
   //   (~x) | y  -->  ~(x & (~y))

log.source_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

